# Using Redis for Idempotency
def process_payment(idempotency_key, amount):
    if redis.exists(idempotency_key):
        return redis.get(idempotency_key)

    result = bank.charge(amount)
    redis.set(idempotency_key, result, ex=86400)
    return result
```

